javascript:
// ===== MASTER TASK BOARD v3 â Seven Labs Vision =====
// All-projects task board with full CRUD, async loading for Frappe Website
// No emoji characters - uses plain text to avoid encoding issues

var mtb_allTasks=[];var mtb_allProjects=[];var mtb_allTaskLists=[];var mtb_allEmployees=[];
var mtb_filters={project:'',status:'',priority:'',assignee:'',startFrom:'',startTo:''};

// ââ Custom Modal Helper (Bootstrap 3) ââ
function mtb_modal(title, fields, primaryLabel, primaryCallback) {
var modalId = 'mtb_modal_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
var html = '<div class="modal fade" id="' + modalId + '" tabindex="-1" role="dialog" aria-hidden="true" style="display:none;">';
html += '<div class="modal-dialog" style="width:500px;">';
html += '<div class="modal-content" style="border-radius:6px;box-shadow:0 2px 8px rgba(0,0,0,0.15);">';
html += '<div class="modal-header" style="border-bottom:1px solid #E2E8F0;padding:15px;background:#F7FAFC;">';
html += '<button type="button" class="close" data-dismiss="modal" style="opacity:0.7;font-size:24px;padding:0;background:none;border:none;cursor:pointer;">&#215;</button>';
html += '<h4 class="modal-title" style="margin:0;font-weight:600;color:#2d3436;font-size:15px;">' + title + '</h4>';
html += '</div>';
html += '<div class="modal-body" style="padding:20px;">';
fields.forEach(function(f) {
var reqMark = f.required ? '<span style="color:#E53E3E;margin-left:2px;">*</span>' : '';
html += '<div style="margin-bottom:14px;">';
html += '<label style="display:block;margin-bottom:4px;font-weight:500;color:#2d3436;font-size:12px;">' + f.label + reqMark + '</label>';
if (f.type === 'text') {
html += '<input type="text" class="form-control mtb_field" data-field="' + f.name + '" value="' + (f.default || '') + '" style="padding:6px 8px;border:1px solid #CBD5E0;border-radius:4px;font-size:12px;width:100%;box-sizing:border-box;" />';
} else if (f.type === 'select') {
html += '<select class="form-control mtb_field" data-field="' + f.name + '" style="padding:6px 8px;border:1px solid #CBD5E0;border-radius:4px;font-size:12px;width:100%;box-sizing:border-box;">';
html += '<option value="">-- Select --</option>';
if (f.options && Array.isArray(f.options)) {
f.options.forEach(function(opt) {
var sel = (f.default && opt.value === f.default) ? ' selected' : '';
html += '<option value="' + opt.value + '"' + sel + '>' + opt.text + '</option>';
});
}
html += '</select>';
} else if (f.type === 'date') {
html += '<input type="date" class="form-control mtb_field" data-field="' + f.name + '" value="' + (f.default || '') + '" style="padding:6px 8px;border:1px solid #CBD5E0;border-radius:4px;font-size:12px;width:100%;box-sizing:border-box;" />';
} else if (f.type === 'number') {
var minA = f.min !== undefined ? ' min="' + f.min + '"' : '';
var maxA = f.max !== undefined ? ' max="' + f.max + '"' : '';
html += '<input type="number" class="form-control mtb_field" data-field="' + f.name + '" value="' + (f.default || 0) + '" style="padding:6px 8px;border:1px solid #CBD5E0;border-radius:4px;font-size:12px;width:100%;box-sizing:border-box;"' + minA + maxA + ' />';
}
html += '</div>';
});
html += '</div>';
html += '<div class="modal-footer" style="border-top:1px solid #E2E8F0;padding:12px 15px;background:#F7FAFC;">';
html += '<button type="button" class="btn btn-default" data-dismiss="modal">Cancel</button>';
html += '<button type="button" class="btn btn-primary mtb_primary_btn" style="font-weight:600;">' + primaryLabel + '</button>';
html += '</div></div></div></div>';
$('body').append(html);
var $modal = $('#' + modalId);
$modal.find('.mtb_primary_btn').on('click', function() {
var valid = true;
var values = {};
$modal.find('.mtb_field').each(function() {
var $f = $(this);
var fn = $f.data('field');
var fObj = fields.find(function(x) { return x.name === fn; });
var v = $f.val();
if (fObj && fObj.required && !v) { valid = false; $f.css('border-color', '#E53E3E'); }
else { $f.css('border-color', '#CBD5E0'); }
values[fn] = v;
});
if (!valid) { frappe.show_alert({message: 'Please fill required fields', indicator: 'red'}); return; }
$modal.modal('hide');
if (primaryCallback) primaryCallback(values);
});
$modal.on('hidden.bs.modal', function() { $modal.remove(); });
$modal.modal('show');
return $modal;
}

// ââ Bootstrap (async with frappe.xcall) ââ
function mtb_init(){
if(!$('#master-task-board').length)return;
frappe.xcall('frappe.client.get_list',{doctype:'User',fields:['name','full_name'],filters:{enabled:1},limit_page_length:500})
.then(function(emps){mtb_allEmployees=emps||[];
return frappe.xcall('frappe.client.get_list',{doctype:'Project',fields:['name','project_name','status'],filters:{},order_by:'project_name asc',limit_page_length:500});
}).then(function(projs){mtb_allProjects=projs||[];
return frappe.xcall('frappe.client.get_list',{doctype:'Task List',fields:['name','title','project'],limit_page_length:500});
}).then(function(tls){mtb_allTaskLists=tls||[];
return mtb_load_tasks_async();
}).then(function(tasks){mtb_allTasks=tasks||[];
mtb_populate_filter_dropdowns();mtb_render_board();mtb_attach_filter_events();mtb_attach_header_events();$('#mtb-loading').hide();
}).catch(function(e){console.error('MTB init error',e);$('#mtb-loading').hide();});
}

function mtb_load_tasks_async(){
var filters={};
if(mtb_filters.project)filters.project=mtb_filters.project;
if(mtb_filters.status)filters.status=mtb_filters.status;
if(mtb_filters.priority)filters.priority=mtb_filters.priority;
if(mtb_filters.startFrom&&mtb_filters.startTo){filters.exp_start_date=['between',[mtb_filters.startFrom,mtb_filters.startTo]];}
else if(mtb_filters.startFrom){filters.exp_start_date=['>=',mtb_filters.startFrom];}
else if(mtb_filters.startTo){filters.exp_start_date=['<=',mtb_filters.startTo];}
return frappe.xcall('frappe.client.get_list',{doctype:'Task',filters:filters,fields:['name','subject','status','priority','exp_start_date','exp_end_date','_assign','is_group','parent_task','progress','custom_task_list','project'],order_by:'project asc, creation asc',limit_page_length:0}).then(function(tasks){
tasks=tasks||[];
if(mtb_filters.assignee){tasks=tasks.filter(function(t){if(!t._assign)return false;try{return JSON.parse(t._assign).indexOf(mtb_filters.assignee)>=0;}catch(e){return false;}});}
return tasks;
});
}

frappe.ready(function(){setTimeout(mtb_init,300);});

// ââ Filter Dropdowns ââ
function mtb_populate_filter_dropdowns(){
var $proj=$('#mtb-filter-project');$proj.find('option:not(:first)').remove();
mtb_allProjects.forEach(function(p){$proj.append('<option value="'+p.name+'">'+(p.project_name||p.name)+'</option>');});
var $assignee=$('#mtb-filter-assignee');$assignee.find('option:not(:first)').remove();
mtb_allEmployees.forEach(function(emp){if(emp.full_name){$assignee.append('<option value="'+emp.name+'">'+emp.full_name+'</option>');}});
}

function mtb_attach_filter_events(){
$('#mtb-filter-project').on('change',function(){mtb_filters.project=$(this).val();mtb_refresh();});
$('#mtb-filter-status').on('change',function(){mtb_filters.status=$(this).val();mtb_refresh();});
$('#mtb-filter-priority').on('change',function(){mtb_filters.priority=$(this).val();mtb_refresh();});
$('#mtb-filter-assignee').on('change',function(){mtb_filters.assignee=$(this).val();mtb_refresh();});
$('#mtb-filter-start-from').on('change',function(){mtb_filters.startFrom=$(this).val();mtb_refresh();});
$('#mtb-filter-start-to').on('change',function(){mtb_filters.startTo=$(this).val();mtb_refresh();});
$('#mtb-clear-filters').on('click',function(){
mtb_filters={project:'',status:'',priority:'',assignee:'',startFrom:'',startTo:''};
$('#mtb-filter-project, #mtb-filter-status, #mtb-filter-priority, #mtb-filter-assignee').val('');
$('#mtb-filter-start-from, #mtb-filter-start-to').val('');
mtb_refresh();
});
}

function mtb_attach_header_events(){
$('#mtb-new-list-btn').on('click',function(){mtb_add_new_task_list();});
$('#mtb-add-task-btn').on('click',function(){mtb_add_new_task();});
$('#mtb-refresh-btn').on('click',function(){mtb_refresh();frappe.show_alert({message:'Refreshed',indicator:'blue'});});
}

// ââ Refresh (async) ââ
function mtb_refresh(){
Promise.all([
mtb_load_tasks_async(),
frappe.xcall('frappe.client.get_list',{doctype:'Task List',fields:['name','title','project'],limit_page_length:500})
]).then(function(results){
mtb_allTasks=results[0]||[];
mtb_allTaskLists=results[1]||[];
mtb_render_board();
});
}

// ââ Render Board ââ
function mtb_render_board(){
var total=mtb_allTasks.length;
$('#mtb-task-count').text(total+' task'+(total!==1?'s':''));
var projectGroups={};
mtb_allTasks.forEach(function(t){var proj=t.project||'__no_project__';if(!projectGroups[proj])projectGroups[proj]=[];projectGroups[proj].push(t);});
var html='';
var projectNames=Object.keys(projectGroups).sort();
projectNames.forEach(function(projKey){
var projTasks=projectGroups[projKey];
var projName=projKey==='__no_project__'?'No Project':projKey;
var projObj=mtb_allProjects.find(function(p){return p.name===projKey;});
var projDisplay=projObj?(projObj.project_name||projObj.name):projName;

// Project header
html+='<div class="mtb-project-group" style="margin-bottom:16px;">';
html+='<div style="display:flex;justify-content:space-between;align-items:center;padding:8px 12px;background:linear-gradient(to right,#EBF8FF,#E6FFFA);border:1px solid #BEE3F8;border-radius:6px 6px 0 0;cursor:pointer;" onclick="mtb_toggle_project(this)">';
html+='<div style="display:flex;align-items:center;gap:8px;">';
html+='<span style="font-size:11px;">&#9660;</span>';
html+='<span style="font-weight:700;font-size:14px;color:#2B6CB0;">'+projDisplay+'</span>';
html+='<span style="background:#BEE3F8;color:#2B6CB0;font-size:10px;padding:2px 8px;border-radius:8px;font-weight:600;">'+projTasks.length+'</span>';
if(projKey!=='__no_project__'){html+='<a href="/app/project/'+projKey+'" style="font-size:10px;color:#718096;text-decoration:none;" title="Open project">&#8599;</a>';}
html+='</div></div>';

// Project content
html+='<div class="mtb-project-content" style="border:1px solid #E2E8F0;border-top:none;border-radius:0 0 6px 6px;">';

// Task Lists for this project
var projTaskLists=mtb_allTaskLists.filter(function(tl){return tl.project===projKey;});
projTaskLists.forEach(function(tl){
var listTasks=projTasks.filter(function(t){return t.custom_task_list===tl.name&&!t.parent_task;});
var listSubtasks=projTasks.filter(function(t){return t.custom_task_list===tl.name&&t.parent_task;});
var totalInList=listTasks.length+listSubtasks.length;

html+='<div class="task-list-group" style="background:#fff;border-bottom:1px solid #E2E8F0;">';
html+='<div style="display:flex;justify-content:space-between;align-items:center;padding:6px 12px;background:linear-gradient(to right,#F7FAFC,#EDF2F7);border-bottom:1px solid #E2E8F0;">';
html+='<div style="display:flex;align-items:center;gap:8px;">';
html+='<span class="mtb-editable-task-list" data-name="'+tl.name+'" data-project="'+projKey+'" style="font-weight:600;font-size:12px;color:#2D3748;cursor:pointer;">'+(tl.title||tl.name)+'</span>';
html+='<span style="background:#E2E8F0;color:#4A5568;font-size:10px;padding:2px 6px;border-radius:8px;font-weight:600;">'+totalInList+'</span>';
html+='</div>';
html+='<div style="display:flex;gap:6px;">';
html+='<button class="btn btn-xs" onclick="mtb_add_task_to_list(\''+tl.name.replace(/'/g,"\\'")+'\',\''+projKey.replace(/'/g,"\\'")+'\')\" style="background:#EBF8FF;color:#2B6CB0;border:1px solid #BEE3F8;font-size:10px;padding:2px 8px;">+ Task</button>';
html+='<button class="btn btn-xs" onclick="mtb_delete_task_list(\''+tl.name.replace(/'/g,"\\'")+'\')\" style="background:#FFF5F5;color:#E53E3E;border:1px solid #FED7D7;font-size:10px;padding:2px 6px;">&#10005;</button>';
html+='</div></div>';

if(totalInList>0){html+='<div style="overflow-x:auto;">'+mtb_build_task_table(listTasks,projTasks)+'</div>';}
else{html+='<div style="padding:12px;text-align:center;color:#A0AEC0;font-size:11px;">No tasks in this list</div>';}
html+='</div>';
});

// Unassigned tasks
var unassigned=projTasks.filter(function(t){return !t.custom_task_list&&!t.parent_task;});
var unassignedSubs=projTasks.filter(function(t){return !t.custom_task_list&&t.parent_task;});
var unassignedTotal=unassigned.length+unassignedSubs.length;
if(unassignedTotal>0||projTasks.length===0){
html+='<div class="task-list-group" style="background:#fff;border-bottom:1px solid #E2E8F0;">';
html+='<div style="display:flex;justify-content:space-between;align-items:center;padding:6px 12px;background:linear-gradient(to right,#FAFBFC,#F0F0F0);border-bottom:1px solid #E2E8F0;">';
html+='<div style="display:flex;align-items:center;gap:8px;">';
html+='<span style="font-weight:600;font-size:12px;color:#718096;">Unassigned Tasks</span>';
html+='<span style="background:#E2E8F0;color:#4A5568;font-size:10px;padding:2px 6px;border-radius:8px;font-weight:600;">'+unassignedTotal+'</span>';
html+='</div>';
html+='<button class="btn btn-xs" onclick="mtb_add_new_task_for_project(\''+projKey.replace(/'/g,"\\'")+'\')\" style="background:#EBF8FF;color:#2B6CB0;border:1px solid #BEE3F8;font-size:10px;padding:2px 8px;">+ Task</button>';
html+='</div>';
if(unassignedTotal>0){html+='<div style="overflow-x:auto;">'+mtb_build_task_table(unassigned,projTasks)+'</div>';}
else{html+='<div style="padding:12px;text-align:center;color:#A0AEC0;font-size:11px;">No tasks yet. Click + Task to create one.</div>';}
html+='</div>';
}
html+='</div></div>';
});

if(projectNames.length===0){html='<div style="padding:40px;text-align:center;color:#A0AEC0;font-size:14px;">No tasks found. Adjust filters or click "+ Add Task" to create one.</div>';}
$('#mtb-groups').html(html);
mtb_attach_task_events();
}

// ââ Build Task Table ââ
function mtb_build_task_table(parentTasks,allProjectTasks){
var h='<table style="width:100%;table-layout:fixed;min-width:1100px;border-collapse:collapse;font-size:11px;">';
h+='<thead style="background:#F7FAFC;border-bottom:1px solid #CBD5E0;"><tr>';
h+='<th style="padding:6px 8px;text-align:left;border-right:1px solid #E2E8F0;font-weight:600;color:#4A5568;width:200px;">Task</th>';
h+='<th style="padding:6px 8px;text-align:center;border-right:1px solid #E2E8F0;font-weight:600;color:#4A5568;width:110px;">Project</th>';
h+='<th style="padding:6px 8px;text-align:center;border-right:1px solid #E2E8F0;font-weight:600;color:#4A5568;width:95px;">Status</th>';
h+='<th style="padding:6px 8px;text-align:center;border-right:1px solid #E2E8F0;font-weight:600;color:#4A5568;width:75px;">Priority</th>';
h+='<th style="padding:6px 8px;text-align:center;border-right:1px solid #E2E8F0;font-weight:600;color:#4A5568;width:90px;">Start Date</th>';
h+='<th style="padding:6px 8px;text-align:center;border-right:1px solid #E2E8F0;font-weight:600;color:#4A5568;width:90px;">End Date</th>';
h+='<th style="padding:6px 8px;text-align:center;border-right:1px solid #E2E8F0;font-weight:600;color:#4A5568;width:110px;">Assigned To</th>';
h+='<th style="padding:6px 8px;text-align:center;border-right:1px solid #E2E8F0;font-weight:600;color:#4A5568;width:65px;">Progress</th>';
h+='<th style="padding:6px 8px;text-align:center;font-weight:600;color:#4A5568;width:70px;">Actions</th>';
h+='</tr></thead><tbody>';
parentTasks.forEach(function(task){
h+=mtb_render_task_row(task,0);
var subs=allProjectTasks.filter(function(t){return t.parent_task===task.name;});
subs.forEach(function(sub){h+=mtb_render_task_row(sub,1);});
});
h+='</tbody></table>';
return h;
}

// ââ Render Task Row ââ
function mtb_render_task_row(task,level){
var indent=level>0?'padding-left:24px;':'';
var prefix=level>0?'<span style="color:#CBD5E0;margin-right:4px;">&#9492;</span> ':'';
var rowBg=level>0?'background:#FAFBFC;':'';
var assignedEmail='';
if(task._assign){try{var arr=JSON.parse(task._assign);if(arr.length)assignedEmail=arr[0];}catch(e){}}
var startDt=task.exp_start_date?task.exp_start_date.split(' ')[0]:'';
var endDt=task.exp_end_date?task.exp_end_date.split(' ')[0]:'';
var startDisplay=startDt?mtb_format_date_display(startDt):'';
var endDisplay=endDt?mtb_format_date_display(endDt):'';
var statusBg={Open:'#EBF8FF',Working:'#FFFFF0','Pending Review':'#FAF5FF',Completed:'#F0FFF4',Cancelled:'#F7FAFC',Overdue:'#FFF5F5'};
var statusColors={Open:'#3182CE',Working:'#D69E2E','Pending Review':'#805AD5',Completed:'#38A169',Cancelled:'#A0AEC0',Overdue:'#E53E3E'};
var priBg={Low:'#F0FFF4',Medium:'#FFFFF0',High:'#FFF5F5',Urgent:'#FFF5F5'};
var priColors={Low:'#38A169',Medium:'#D69E2E',High:'#E53E3E',Urgent:'#C53030'};
var progress=task.progress||0;
var projObj=mtb_allProjects.find(function(p){return p.name===task.project;});
var projDisplay=projObj?(projObj.project_name||projObj.name):(task.project||'-');

var row='<tr data-task="'+task.name+'" style="border-bottom:1px solid #E2E8F0;'+rowBg+'">';

// Task name
row+='<td style="'+indent+'padding:6px 8px;border-right:1px solid #E2E8F0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">';
row+=prefix+'<a href="/app/task/'+task.name+'" style="color:#2B6CB0;text-decoration:none;font-weight:500;" title="'+(task.subject||task.name)+'">'+(task.subject||task.name)+'</a></td>';

// Project
row+='<td style="padding:6px 8px;border-right:1px solid #E2E8F0;text-align:center;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">';
if(task.project){row+='<a href="/app/project/'+task.project+'" style="color:#2B6CB0;text-decoration:none;font-size:10px;" title="'+projDisplay+'">'+projDisplay+'</a>';}
else{row+='<span style="color:#A0AEC0;font-size:10px;">-</span>';}
row+='</td>';

// Status
row+='<td style="padding:6px 8px;border-right:1px solid #E2E8F0;text-align:center;"><select class="mtb-field-select" data-task="'+task.name+'" data-field="status" style="appearance:menulist;padding:2px 4px;border:1px solid #E2E8F0;border-radius:4px;font-size:10px;width:100%;background:'+(statusBg[task.status]||'#fff')+';color:'+(statusColors[task.status]||'#4A5568')+';font-weight:600;cursor:pointer;">';
['Open','Working','Pending Review','Overdue','Completed','Cancelled'].forEach(function(s){row+='<option value="'+s+'"'+(task.status===s?' selected':'')+'>'+s+'</option>';});
row+='</select></td>';

// Priority
row+='<td style="padding:6px 8px;border-right:1px solid #E2E8F0;text-align:center;"><select class="mtb-field-select" data-task="'+task.name+'" data-field="priority" style="appearance:menulist;padding:2px 4px;border:1px solid #E2E8F0;border-radius:4px;font-size:10px;width:100%;background:'+(priBg[task.priority]||'#fff')+';color:'+(priColors[task.priority]||'#4A5568')+';font-weight:600;cursor:pointer;">';
['Low','Medium','High','Urgent'].forEach(function(p){row+='<option value="'+p+'"'+(task.priority===p?' selected':'')+'>'+p+'</option>';});
row+='</select></td>';

// Start date
row+='<td style="padding:6px 8px;border-right:1px solid #E2E8F0;text-align:center;"><div class="mtb-date-display" data-task="'+task.name+'" data-field="exp_start_date" data-value="'+startDt+'" style="cursor:pointer;padding:3px 4px;border:1px solid transparent;border-radius:4px;background:#F7FAFC;font-size:10px;display:flex;align-items:center;justify-content:center;gap:2px;min-height:24px;">';
row+=startDisplay?'<span>'+startDisplay+'</span>':'<span style="color:#A0AEC0;">Set date</span>';
row+='</div></td>';

// End date
row+='<td style="padding:6px 8px;border-right:1px solid #E2E8F0;text-align:center;"><div class="mtb-date-display" data-task="'+task.name+'" data-field="exp_end_date" data-value="'+endDt+'" style="cursor:pointer;padding:3px 4px;border:1px solid transparent;border-radius:4px;background:#F7FAFC;font-size:10px;display:flex;align-items:center;justify-content:center;gap:2px;min-height:24px;">';
row+=endDisplay?'<span>'+endDisplay+'</span>':'<span style="color:#A0AEC0;">Set date</span>';
row+='</div></td>';

// Assigned to
row+='<td style="padding:6px 8px;border-right:1px solid #E2E8F0;text-align:center;"><select class="mtb-assigned-select" data-task="'+task.name+'" style="appearance:menulist;padding:2px 4px;border:1px solid #E2E8F0;border-radius:4px;font-size:10px;width:100%;cursor:pointer;">';
row+='<option value="">-- Unassigned --</option>';
mtb_allEmployees.forEach(function(emp){row+='<option value="'+emp.name+'"'+(assignedEmail===emp.name?' selected':'')+'>'+(emp.full_name||emp.name)+'</option>';});
row+='</select></td>';

// Progress
row+='<td style="padding:6px 8px;border-right:1px solid #E2E8F0;text-align:center;"><div style="display:flex;flex-direction:column;align-items:center;gap:2px;"><div style="width:100%;background:#E2E8F0;border-radius:3px;height:5px;overflow:hidden;"><div style="background:'+(progress>=100?'#38A169':'#2490EF')+';height:100%;width:'+progress+'%;border-radius:3px;"></div></div><span class="mtb-progress-text" style="font-size:10px;color:#718096;cursor:pointer;" data-task="'+task.name+'">'+progress+'%</span></div></td>';

// Actions
row+='<td style="padding:6px 8px;text-align:center;"><div style="display:flex;gap:3px;justify-content:center;">';
