$('.mtb-editable-task-list').off('click').on('click',function(){
var oldName=$(this).data('name');
var currentText=$(this).text().trim();
var $el=$(this);
var input=$('<input type="text" class="form-control input-xs" style="height:22px;font-size:11px;width:150px;">');
input.val(currentText);$el.replaceWith(input);input.focus();
input.on('blur keypress',function(e){
if(e.type==='blur'||e.which===13){
var newName=input.val().trim();
if(!newName||newName===currentText){mtb_refresh();return;}
frappe.call({method:'frappe.client.rename_doc',args:{doctype:'Task List',old_name:oldName,new_name:newName,merge:0},callback:function(r){if(!r.exc){frappe.show_alert({message:'Renamed',indicator:'green'});mtb_refresh();}}});
}
});
});
}

// ââ Update Task Field ââ
function mtb_update_task_field(taskName,fieldName,value){
frappe.call({method:'frappe.client.set_value',args:{doctype:'Task',name:taskName,fieldname:fieldName,value:value},callback:function(r){
